# -----------------------------------------------------------------------

# Load the outer JSON
outer_payload = json.loads(response_from_preprocessing_str)

# Get the string that contains the DataFrame JSON
processed_data_json_string_from_service = outer_payload['processed_data_json']

# Load the inner JSON (the DataFrame representation)
df_dict = json.loads(processed_data_json_string_from_service)

# Extract the 'data' part, which is a list of lists
# Each inner list is a row, and since 'Ea' is the only column, each inner list has one element.
all_ea_values = [item[0] for item in df_dict['data'] if item] # item might be None if a row was all NaN before to_json
# Filter out None values that might have been introduced if a row was entirely NaN before to_json
# (though KNNImputer should have filled them, this is a safe check)
all_ea_values = [val for val in all_ea_values if val is not None]


print(f"Total number of data points extracted: {len(all_ea_values)}")

# --- Configuration for forecasting service input ---
N_TIMESTEPS_FORECAST = 288 # Your LSTM's requirement
# -------------------------------------------------

if len(all_ea_values) >= N_TIMESTEPS_FORECAST:
    # Select the last N_TIMESTEPS_FORECAST points
    sequence_for_forecasting_model = all_ea_values[-N_TIMESTEPS_FORECAST:]
    print(f"Selected last {N_TIMESTEPS_FORECAST} points for forecasting model.")
    # print(f"Sequence: {sequence_for_forecasting_model}") # Can be very long

    # Create the payload for the forecasting service
    # This depends on what your /forecast-and-post endpoint *actually* expects
    # Is it the "processed_data_json" string again, or a simpler "sequence_data" key?
    # Based on your error "Missing processed_data_json or target_device_access_token",
    # it still expects "processed_data_json".

    # So, we need to reconstruct a "processed_data_json" string containing ONLY these 288 points.
    # This is a bit circular if the forecasting service is then going to parse it again.
    # It would be more efficient if the forecasting service could accept a direct list of numbers.

    # Option 1: Forecasting service expects a direct sequence (e.g. {"sequence_data": [...]})
    # This is often simpler if this service isn't also doing preprocessing.
    # forecasting_payload = {
    #     "sequence_data": sequence_for_forecasting_model, # Assuming it wants a flat list
    #     "target_device_access_token": "vZhSgD0h19Hjdy4MwrW4" # Your token
    # }

    # Option 2: Forecasting service *still* expects the "processed_data_json" string format,
    # but containing only the 288 points.
    # We also need the corresponding 288 timestamps for the 'index' part.
    timestamps_for_288 = df_dict['index'][-N_TIMESTEPS_FORECAST:]
    data_for_288 = [[val] for val in sequence_for_forecasting_model] # Needs to be list of lists

    payload_for_fc_service_dict = {
        "columns": ["Ea"],
        "index": timestamps_for_288,
        "data": data_for_288
    }
    processed_data_json_for_fc_service_str = json.dumps(payload_for_fc_service_dict)

    forecasting_payload = {
        "processed_data_json": processed_data_json_for_fc_service_str,
        "target_device_access_token": "vZhSgD0h19Hjdy4MwrW4"
    }

    # Save this new payload to a file to be used with curl
    with open("payload_for_forecasting_service.json", "w") as f:
        json.dump(forecasting_payload, f, indent=4)
    print("payload_for_forecasting_service.json created successfully.")
    print("You can now use this file with curl for the /forecast-and-post endpoint.")

else:
    print(f"Not enough data points ({len(all_ea_values)}) to meet the forecasting model's requirement of {N_TIMESTEPS_FORECAST} timesteps.")